// Colors from the app's pace palette
const ROUTES = [
  { d: ROUTE_1, color: "#00ffcc" }, // green / ahead of pace
  { d: ROUTE_2, color: "#ff8844" }, // amber / behind pace
  { d: ROUTE_3, color: "#FC4C02" }, // strava orange
] as const;

// Animation timing (seconds) — one route visible at a time
const DRAW_DURATION = 4;
const FADE_IN_DURATION = 1;
const HOLD_DURATION = 2;
const FADE_OUT_DURATION = 1;
const ACTIVE_DURATION = DRAW_DURATION + HOLD_DURATION + FADE_OUT_DURATION; // 8s
const GAP = 1; // breathing room between routes
const SLOT = ACTIVE_DURATION + GAP; // 9s per route
const CYCLE = SLOT * ROUTES.length; // 27s full cycle

/**
 * A single animated route path.
 * Uses requestAnimationFrame for the draw-on (dashoffset) and opacity cycling.
 */
const TRACER_FRAC = 0.03;

function AnimatedRoute({
  d,
  color,
  strokeWidth,
  delay,
  reducedMotion,
}: {
  d: string;
  color: string;
  strokeWidth: number;
  delay: number;
  reducedMotion: boolean;
}) {
  const pathRef = useRef<SVGPathElement>(null);
  const tracerRef = useRef<SVGPathElement>(null);
  const totalLengthRef = useRef<number | null>(null);

  const animate = useCallback(
    (time: number) => {
      const path = pathRef.current;
      const tracer = tracerRef.current;
      if (!path || !tracer) return;

      if (totalLengthRef.current === null) {
        totalLengthRef.current = path.getTotalLength();
      }
      const totalLength = totalLengthRef.current;
      const tracerLen = totalLength * TRACER_FRAC;

      if (reducedMotion) {
        path.style.strokeDasharray = `${totalLength}`;
        path.style.strokeDashoffset = "0";
        path.style.opacity = "0.3";
        tracer.style.opacity = "0";
        return;
      }

      const t = ((time / 1000 - delay) % CYCLE + CYCLE) % CYCLE;

      let opacity: number;
      let progress: number;

      if (t < DRAW_DURATION) {
        const drawT = t / DRAW_DURATION;
        progress = drawT < 0.5
          ? 4 * drawT * drawT * drawT
          : 1 - Math.pow(-2 * drawT + 2, 3) / 2;
        opacity = Math.min(1, t / FADE_IN_DURATION);
      } else if (t < DRAW_DURATION + HOLD_DURATION) {
        progress = 1;
        opacity = 1;
      } else if (t < ACTIVE_DURATION) {
        const fadeT = (t - DRAW_DURATION - HOLD_DURATION) / FADE_OUT_DURATION;
        progress = 1;
        opacity = 1 - fadeT * fadeT;
      } else {
        progress = 0;
        opacity = 0;
      }

      // Path draws on via dashoffset
      path.style.strokeDasharray = `${totalLength}`;
      path.style.strokeDashoffset = `${totalLength * (1 - progress)}`;
      path.style.opacity = `${opacity}`;

      // Tracer: bright dot at leading edge during draw phase
      const drawnLen = progress * totalLength;
      if (t < DRAW_DURATION && drawnLen > 0.5) {
        const visTr = Math.min(tracerLen, drawnLen);
        tracer.style.strokeDasharray = `${visTr} ${totalLength}`;
        tracer.style.strokeDashoffset = `${visTr - drawnLen}`;
        tracer.style.opacity = `${opacity}`;
      } else {
        tracer.style.opacity = "0";
      }
    },
    [delay, reducedMotion]
  );

  const animateRef = useRef(animate);
  animateRef.current = animate;

  useEffect(() => {
    if (reducedMotion) {
      requestAnimationFrame((t) => animateRef.current(t));
      return;
    }

    let rafId: number;
    const loop = (time: number) => {
      animateRef.current(time);
      rafId = requestAnimationFrame(loop);
    };
    rafId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(rafId);
  }, [reducedMotion]);

  return (
    <g>
      <path
        ref={pathRef}
        d={d}
        fill="none"
        stroke={color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeLinejoin="round"
        opacity={0}
      />
      <path
        ref={tracerRef}
        d={d}
        fill="none"
        stroke={color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeLinejoin="round"
        opacity={0}
      />
    </g>
  );
}

export function RouteBackground() {
  const reducedMotion = useReducedMotion() ?? false;

  return (
    <motion.div
      className="absolute inset-0 z-0"
      aria-hidden="true"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: reducedMotion ? 0 : 1.5, ease: [0.25, 0.1, 0.25, 1] }}
    >
      {/* Ambient layer — medium blur creates color wash */}
      <div
        className="absolute inset-0"
        style={{ filter: "blur(16px)", opacity: 0.5 }}
      >
        <svg
          viewBox="0 0 800 800"
          preserveAspectRatio="xMidYMid slice"
          className="absolute inset-0 w-full h-full"
        >
          {/* Scale routes smaller, centered in viewBox */}
          <g transform="translate(400,400) scale(0.55) translate(-400,-400)">
            {ROUTES.map((route, i) => (
              <AnimatedRoute
                key={i}
                d={route.d}
                color={route.color}
                strokeWidth={16}
                delay={i * SLOT}
                reducedMotion={reducedMotion}
              />
            ))}
          </g>
        </svg>
      </div>

      {/* Detail layer — lighter blur shows route shape */}
      <div
        className="absolute inset-0"
        style={{ filter: "blur(12px)", opacity: 0.3 }}
      >
        <svg
          viewBox="0 0 800 800"
          preserveAspectRatio="xMidYMid slice"
          className="absolute inset-0 w-full h-full"
        >
          <g transform="translate(400,400) scale(0.55) translate(-400,-400)">
            {ROUTES.map((route, i) => (
              <AnimatedRoute
                key={i}
                d={route.d}
                color={route.color}
                strokeWidth={5}
                delay={i * SLOT}
                reducedMotion={reducedMotion}
              />
            ))}
          </g>
        </svg>
      </div>
    </motion.div>
  );
}
